#!/usr/bin/env bash
# Installs the project's pre-commit hooks into .git/hooks/.
# Safe to re-run; overwrites any existing pre-commit hook.
set -euo pipefail

REPO_ROOT="$(git rev-parse --show-toplevel)"
HOOK_DST="$REPO_ROOT/.git/hooks/pre-commit"

cat > "$HOOK_DST" <<'EOF'
#!/usr/bin/env bash
# Auto-generated by scripts/hooks/install.sh — do not edit by hand.
set -euo pipefail
ROOT="$(git rev-parse --show-toplevel)"
"$ROOT/scripts/hooks/pre-commit-migration-journal.sh"
"$ROOT/scripts/hooks/pre-commit-invariants.sh"
EOF
chmod +x "$HOOK_DST"
echo "installed: $HOOK_DST"
